{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires complex logical deduction across a large set of rules. I will split the task into rule extraction/mapping and logical path tracing.",
  "helpers": [
    {
      "label": "rule_mapper",
      "instructions": "Analyze the 45 provided rules and extract all causal relationships or conditional statements involving the butterfly, the fish, and any intermediate entities. Create a directed graph or a list of logical implications where each node is an entity or state and each edge is a rule-based transition."
    },
    {
      "label": "logic_engine",
      "instructions": "Using the directed graph of rules provided by the rule mapper, attempt to find a valid logical path that connects the butterfly's actions to the fish receiving a secret. Determine if the rules provide a definitive yes, a definitive no, or if the information chain is broken or insufficient to reach a conclusion."
    }
  ],
  "synthesis_brief": "Combine the rule map and the logical path analysis to determine if the sequence of events is complete. If the path is broken or the rules do not explicitly link the butterfly to the fish, conclude that the answer is unknown."
}

